                    Path relNames = absNormalized.getNameCount() > 0
                            ? absNormalized.subpath(0, absNormalized.getNameCount())
                            : Paths.get("");
                    target = baseDir.resolve(relNames).normalize();
                }
            } else {
                // 相对路径，直接解析到 BASE_PATH 下
                target = baseDir.resolve(inputPath.normalize()).normalize();
            }

            // 防止路径逃逸（例如使用 ..）
            if (!target.startsWith(baseDir)) {
                return false;
            }

            // 不能将目录当作文件写入
            if (target.equals(baseDir)) {
                return false;
            }

            Path parent = target.getParent();
            if (parent == null) {
                parent = baseDir;
            }

            // 创建父目录
            Files.createDirectories(parent);

            // 路径中任一已存在的目录不能是符号链接（减少穿越攻击风险）
            if (containsSymlinkInPath(baseDir, parent)) {
                return false;
            }

            // 目标如果已存在为目录或符号链接则拒绝
            if (Files.exists(target, LinkOption.NOFOLLOW_LINKS)) {
                if (Files.isDirectory(target) || Files.isSymbolicLink(target)) {
                    return false;
                }
            }

            // 父目录必须可写
            if (!Files.isWritable(parent)) {
                return false;
            }

            // 写入（UTF-8），不存在则创建，存在则覆盖
            try (BufferedWriter writer = Files.newBufferedWriter(
                    target,
                    StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE,
                    StandardOpenOption.TRUNCATE_EXISTING,
                    StandardOpenOption.WRITE)) {
                writer.write(content == null ? "" : content);
            }

            return true;
        } catch (InvalidPathException | FileAlreadyExistsException e) {
            return false;
        } catch (IOException e) {
            return false;
        }
    }

    // 检查 baseDir -> targetParent 的路径中是否包含已存在的符号链接
    private boolean containsSymlinkInPath(Path baseDir, Path targetParent) throws IOException {
        if (!targetParent.startsWith(baseDir)) {
            return true;
        }
        Path rel = baseDir.relativize(targetParent);
        Path current = baseDir;
        for (Path name : rel) {
            current = current.resolve(name);
            if (Files.exists(current, LinkOption.NOFOLLOW_LINKS) && Files.isSymbolicLink(current)) {
                return true;
            }
        }
        return false;
    }
